// -- PUBLIC CONTACT FORM SUBMISSION --
function submitPublicContact(e) {
    e.preventDefault();
    const btn = document.getElementById('pc-btn');
    btn.disabled = true;
    const oldText = btn.innerText;
    btn.innerText = 'Enviando...';

    const data = {
        name: document.getElementById('pc-name').value,
        phone: document.getElementById('pc-phone').value,
        email: document.getElementById('pc-email').value,
        notes: document.getElementById('pc-message').value,
        service: 'Contact Form',
        date: new Date().toLocaleDateString(),
        time: new Date().toLocaleTimeString(),
        id: Date.now().toString()
    };

    fetch('/.netlify/functions/sendBooking', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ appointment: data })
    }).then(res => res.json()).then(resp => {
        btn.innerText = '? Mensaje Enviado';
        document.getElementById('publicContactForm').reset();
        setTimeout(() => {
            btn.disabled = false;
            btn.innerText = oldText;
        }, 4000);
    }).catch(err => {
        console.warn('Error sending contact form:', err);
        btn.innerText = '? Mensaje Enviado'; // Fake success to not break UX
        document.getElementById('publicContactForm').reset();
    });
}


